/**
 * Identity composer for Codedank Web ID packages.
 *
 * @example
 * import { Effect } from "effect";
 * import { S } from "effect";
 * import { A, O, P, R } from "effect";
 * import { $CodedankWebId } from "@beep/identity";
 * 
 * // Example of decoding a valid Codedank Web ID
 * const validInput = "https://codedank.com/web/1234567890abcdef";
 * const result = S.decodeUnknown($CodedankWebId)(validInput);
 * assert.deepStrictEqual(result, {
 *   _id: "@beep/codedank-web",
 *   value: validInput
 * });
 * 
 * // Example of decoding an invalid Codedank Web ID
 * const invalidInput = "invalid-url";
 * const errorResult = S.decodeUnknown($CodedankWebId)(invalidInput);
 * assert.ok(O.isSome(errorResult));
 * 
 * @category packages
 * @since 1.0.0
 */

/**
 * Creates a schema constructor that can be used to build schemas with specific output and error types.
 *
 * @example
 * import { Schema as S, Effect as E } from "effect";
 * import { Fn } from "@beep/schema";
 *
 * const schema = Fn({
 *   output: S.string,
 *   error: S.number
 * });
 *
 * const result = E.runSync(Schema.decodeUnknown(schema, "hello"));
 * // Effect.succeed("hello")
 *
 * @category constructors
 * @since 1.0.0
 */

/**
 * Identity composer for DuckDB identifiers.
 *
 * @example
 * import { Identity } from "@beep/identity";
 * import { S } from "effect";
 *
 * const schema = Identity.schema($DuckdbId);
 * const decoded = S.decodeUnknown(schema)("duckdb://my_table");
 * console.log(decoded); // { _id: "duckdb://my_table" }
 */
